import React, { useState, useEffect, useRef, useCallback } from "react";
import { io } from "socket.io-client";

const SERVER_URL = "http://localhost:3000";

// Socket singleton — created once, NOT auto-connected
// Token is injected at connect time via socket.auth
const socket = io(SERVER_URL, { autoConnect: false });

// ─────────────────────────────────────────
//  Small reusable components
// ─────────────────────────────────────────

function TypingDots() {
  return (
    <span className="typing-dots">
      <span /><span /><span />
    </span>
  );
}

function MessageBubble({ msg, isOwn }) {
  const isSystem = msg.type === "system";
  if (isSystem) {
    return (
      <div className="msg-system">
        <span className="msg-system-text">{msg.text}</span>
        <span className="msg-time">{formatTime(msg.timestamp)}</span>
      </div>
    );
  }
  return (
    <div className={`msg-row ${isOwn ? "msg-own" : ""}`}>
      <div className="msg-avatar" aria-hidden="true">
        {msg.username.charAt(0).toUpperCase()}
      </div>
      <div className="msg-body">
        <div className="msg-meta">
          <span className="msg-username">{msg.username}</span>
          <span className="msg-time">{formatTime(msg.timestamp)}</span>
        </div>
        <div className="msg-bubble">{msg.text}</div>
      </div>
    </div>
  );
}

function UserPill({ user, isMe }) {
  return (
    <div className={`user-pill ${isMe ? "user-pill-me" : ""}`}>
      <span className="user-pill-dot" aria-hidden="true" />
      <span className="user-pill-avatar">{user.username.charAt(0).toUpperCase()}</span>
      <span className="user-pill-name">{user.username}{isMe && <em> (you)</em>}</span>
    </div>
  );
}

// ─────────────────────────────────────────
//  Helpers
// ─────────────────────────────────────────
function formatTime(iso) {
  if (!iso) return "";
  return new Date(iso).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

// ─────────────────────────────────────────
//  Auth Screen (Login + Register tabs)
// ─────────────────────────────────────────
function AuthScreen({ onAuthSuccess, error, loading }) {
  const [tab, setTab]           = useState("login");   // "login" | "register"
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [confirm,  setConfirm]  = useState("");
  const [localErr, setLocalErr] = useState("");
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, [tab]);

  // Clear fields & errors on tab switch
  function switchTab(t) {
    setTab(t);
    setUsername("");
    setPassword("");
    setConfirm("");
    setLocalErr("");
  }

  function handleSubmit(e) {
    e.preventDefault();
    setLocalErr("");

    if (!username.trim() || !password) {
      setLocalErr("Please fill in all fields.");
      return;
    }
    if (tab === "register") {
      if (password !== confirm) {
        setLocalErr("Passwords do not match.");
        return;
      }
      if (password.length < 6) {
        setLocalErr("Password must be at least 6 characters.");
        return;
      }
    }

    onAuthSuccess(tab, username.trim(), password);
  }

  const displayError = localErr || error;

  return (
    <div className="join-overlay">
      <div className="join-card">
        {/* Logo */}
        <div className="join-logo" aria-hidden="true">
          <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
            <rect width="48" height="48" rx="16" fill="#5865F2"/>
            <path d="M32 16C32 16 28.5 15 24 15C19.5 15 16 16 16 16C14.3 16.7 13 19 13 22V27C13 30 14.3 32 16 32.5L17 35.5L20.5 32.5C21.6 32.8 22.8 33 24 33C25.2 33 26.4 32.8 27.5 32.5L31 35.5L32 32.5C33.7 32 35 30 35 27V22C35 19 33.7 16.7 32 16Z" fill="white"/>
            <circle cx="20" cy="24" r="2" fill="#5865F2"/>
            <circle cx="28" cy="24" r="2" fill="#5865F2"/>
          </svg>
        </div>

        <h1 className="join-title">Descall</h1>
        <p className="join-subtitle">Real-time chat. Jump right in.</p>

        {/* Tabs */}
        <div className="auth-tabs">
          <button
            className={`auth-tab ${tab === "login" ? "auth-tab-active" : ""}`}
            onClick={() => switchTab("login")}
            type="button"
          >
            Login
          </button>
          <button
            className={`auth-tab ${tab === "register" ? "auth-tab-active" : ""}`}
            onClick={() => switchTab("register")}
            type="button"
          >
            Register
          </button>
        </div>

        <form onSubmit={handleSubmit} className="join-form">
          {/* Username */}
          <label className="join-label" htmlFor="auth-username">Username</label>
          <input
            id="auth-username"
            ref={inputRef}
            className={`join-input ${displayError ? "join-input-error" : ""}`}
            type="text"
            placeholder="e.g. cooldev42"
            value={username}
            maxLength={24}
            onChange={(e) => setUsername(e.target.value)}
            autoComplete="username"
            spellCheck={false}
            disabled={loading}
          />

          {/* Password */}
          <label className="join-label" htmlFor="auth-password">Password</label>
          <input
            id="auth-password"
            className={`join-input ${displayError ? "join-input-error" : ""}`}
            type="password"
            placeholder="••••••••"
            value={password}
            maxLength={72}
            onChange={(e) => setPassword(e.target.value)}
            autoComplete={tab === "login" ? "current-password" : "new-password"}
            disabled={loading}
          />

          {/* Confirm password — only for register */}
          {tab === "register" && (
            <>
              <label className="join-label" htmlFor="auth-confirm">Confirm Password</label>
              <input
                id="auth-confirm"
                className={`join-input ${displayError ? "join-input-error" : ""}`}
                type="password"
                placeholder="••••••••"
                value={confirm}
                maxLength={72}
                onChange={(e) => setConfirm(e.target.value)}
                autoComplete="new-password"
                disabled={loading}
              />
            </>
          )}

          {displayError && <p className="join-error">{displayError}</p>}

          <button
            className="join-btn"
            type="submit"
            disabled={loading || !username.trim() || !password}
          >
            {loading
              ? <TypingDots />
              : tab === "login" ? "Login" : "Create Account"
            }
          </button>
        </form>

        {/* Subtle switch link */}
        <p className="auth-switch">
          {tab === "login"
            ? <>No account? <button className="auth-switch-btn" onClick={() => switchTab("register")}>Register</button></>
            : <>Have an account? <button className="auth-switch-btn" onClick={() => switchTab("login")}>Login</button></>
          }
        </p>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────
//  Main Chat Screen
// ─────────────────────────────────────────
function ChatScreen({ me, messages, users, onSend, onLeave, connected }) {
  const [text, setText] = useState("");
  const bottomRef = useRef(null);
  const inputRef  = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  function handleSend(e) {
    e.preventDefault();
    const trimmed = text.trim();
    if (!trimmed || !connected) return;
    onSend(trimmed);
    setText("");
    inputRef.current?.focus();
  }

  function handleKeyDown(e) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend(e);
    }
  }

  return (
    <div className="chat-layout">
      {/* ── Left sidebar: online users ── */}
      <aside className="sidebar">
        <div className="sidebar-header">
          <span className="sidebar-title">Online</span>
          <span className="sidebar-badge">{users.length}</span>
        </div>
        <div className="sidebar-users">
          {users.map((u) => (
            <UserPill key={u.id} user={u} isMe={u.username === me} />
          ))}
          {users.length === 0 && (
            <p className="sidebar-empty">No one else here yet…</p>
          )}
        </div>
        <button className="leave-btn" onClick={onLeave} title="Leave chat">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
            <polyline points="16 17 21 12 16 7"/>
            <line x1="21" y1="12" x2="9" y2="12"/>
          </svg>
          Leave
        </button>
      </aside>

      {/* ── Right: channel + messages + input ── */}
      <div className="chat-area">
        <header className="chat-header">
          <div className="chat-header-left">
            <span className="chat-hash" aria-hidden="true">#</span>
            <span className="chat-channel-name">general</span>
          </div>
          <div className="chat-header-right">
            <span className={`conn-badge ${connected ? "conn-on" : "conn-off"}`}>
              <span className="conn-dot" />
              {connected ? "Connected" : "Reconnecting…"}
            </span>
          </div>
        </header>

        <div className="messages-feed" role="log" aria-live="polite">
          {messages.length === 0 && (
            <div className="feed-empty">
              <p>👋 No messages yet. Say something!</p>
            </div>
          )}
          {messages.map((msg, i) => (
            <MessageBubble key={i} msg={msg} isOwn={msg.username === me} />
          ))}
          <div ref={bottomRef} />
        </div>

        <form className="composer" onSubmit={handleSend}>
          <input
            ref={inputRef}
            className="composer-input"
            type="text"
            placeholder={connected ? `Message #general` : "Reconnecting…"}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            maxLength={1000}
            disabled={!connected}
            autoComplete="off"
            spellCheck
          />
          <button
            className="composer-send"
            type="submit"
            disabled={!text.trim() || !connected}
            aria-label="Send message"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
              <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z"/>
            </svg>
          </button>
        </form>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────
//  Root App — state + socket + auth wiring
// ─────────────────────────────────────────
export default function App() {
  const [phase,     setPhase]     = useState("auth");   // "auth" | "chat"
  const [me,        setMe]        = useState("");
  const [messages,  setMessages]  = useState([]);
  const [users,     setUsers]     = useState([]);
  const [connected, setConnected] = useState(false);
  const [authError, setAuthError] = useState("");
  const [loading,   setLoading]   = useState(false);

  // ── Socket event wiring ────────────────
  useEffect(() => {
    socket.on("connect",    () => setConnected(true));
    socket.on("disconnect", () => setConnected(false));

    socket.on("user:joined", ({ user }) => {
      setMe(user.username);
      setPhase("chat");
      setAuthError("");
      setLoading(false);
    });

    socket.on("message:new", (msg) => {
      setMessages((prev) => [...prev, msg]);
    });

    socket.on("users:update", (list) => {
      setUsers(list);
    });

    socket.on("connect_error", (err) => {
      setAuthError(err.message || "Connection failed.");
      setLoading(false);
      socket.disconnect();
    });

    socket.on("error", ({ message }) => {
      setAuthError(message);
      setLoading(false);
      socket.disconnect();
    });

    return () => {
      socket.off("connect");
      socket.off("disconnect");
      socket.off("user:joined");
      socket.off("message:new");
      socket.off("users:update");
      socket.off("connect_error");
      socket.off("error");
    };
  }, []);

  // ── Auth handler ──────────────────────
  const handleAuth = useCallback(async (mode, username, password) => {
    setAuthError("");
    setLoading(true);

    try {
      // 1. If registering, hit /register first
      if (mode === "register") {
        const regRes = await fetch(`${SERVER_URL}/register`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ username, password }),
        });
        const regData = await regRes.json();
        if (!regRes.ok) {
          setAuthError(regData.error || "Registration failed.");
          setLoading(false);
          return;
        }
      }

      // 2. Login to get JWT
      const loginRes = await fetch(`${SERVER_URL}/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, password }),
      });
      const loginData = await loginRes.json();
      if (!loginRes.ok) {
        setAuthError(loginData.error || "Login failed.");
        setLoading(false);
        return;
      }

      const { token } = loginData;

      // 3. Connect socket with JWT
      socket.auth = { token };
      socket.connect();

    } catch (err) {
      setAuthError("Could not reach the server. Is it running?");
      setLoading(false);
    }
  }, []);

  // ── Send message ───────────────────────
  const handleSend = useCallback((text) => {
    socket.emit("message:send", { text });
  }, []);

  // ── Leave chat ─────────────────────────
  const handleLeave = useCallback(() => {
    socket.disconnect();
    setPhase("auth");
    setMe("");
    setMessages([]);
    setUsers([]);
    setConnected(false);
    setAuthError("");
  }, []);

  // ── Render ────────────────────────────
  if (phase === "auth") {
    return (
      <AuthScreen
        onAuthSuccess={handleAuth}
        error={authError}
        loading={loading}
      />
    );
  }

  return (
    <ChatScreen
      me={me}
      messages={messages}
      users={users}
      onSend={handleSend}
      onLeave={handleLeave}
      connected={connected}
    />
  );
}
